StructuredTextModel.Text:
Size := (SizeOfAry(Torque_Values));

// Reset everything when demanded
IF (Reset) THEN
	Torque_Values := Torque_Values_Init;
	Index := 0;
	Torque_Alarm := FALSE;
END_IF;

IF (Enable) THEN
	// Add a value to the list
	Torque_Values[Index] := Torque_Val;
	
	// Find the average torque for the list
	Torque_Total := 0;
	FOR I := 0 TO 4 DO
		Torque_Total := Torque_Values[I]+Torque_Total;
	END_FOR;
	Torque_Average := Torque_Total/TO_LREAL(Size);
	
	// Test if the average is above the limit
	IF (Torque_Average > Torque_SP) THEN
		Torque_Alarm := TRUE;
	END_IF;
	
	// Increment the index unless doing so goes beyond the size of the list
	IF (Index+1 < Size) THEN
		Index := Index+1;
	ELSE
		Index := 0;
	END_IF;
END_IF;
